-- The Wharf DC events (23 events) from wharfdc.com/upcoming-events.
-- Free waterfront programming: Summer of Soccer, Sunset Cinema, Grooves in the
-- Grove, Rock the Dock, Fourth at The Wharf, Salsa Dance Night. Deduped against
-- existing rows (e.g. the Washingtonian "Sunset Cinema: Catch Me If You Can").
-- Coordinates + address keep them past the enforce-dc trigger. Safe to re-run.
-- Paste into Supabase -> SQL Editor -> Run.
begin;
delete from public.events where source = 'wharf';

-- The Wharf lists Country Line Dancing (Jul 3) as CANCELLED due to extreme heat,
-- but the earlier import-dc-events.sql loaded it as a published event dated today,
-- so it would still surface in the feed. Hide it to match the source.
update public.events
set status = 'hidden', updated_at = now()
where external_id = 'import_countrylinedancingatthewharf_transitpier_2026-07-03';

commit;
